#include "TokenStreamRouter.h"
#include <QDebug>

TokenStreamRouter* TokenStreamRouter::instance() {
    static TokenStreamRouter* s_instance = nullptr;
    static QMutex mutex;
    
    QMutexLocker lock(&mutex);
    if (!s_instance) {
        s_instance = new TokenStreamRouter();
    }
    return s_instance;
}

TokenStreamRouter::TokenStreamRouter(QObject* parent) 
    : QObject(parent) {
}

void TokenStreamRouter::registerHandler(uint32_t streamId, TokenHandler handler) {
    QMutexLocker lock(&m_mutex);
    
    HandlerEntry entry;
    entry.callback = handler;
    entry.ownerThread = QThread::currentThread();
    
    m_handlers[streamId] = entry;
    qInfo() << "Registered token handler for stream" << streamId;
}

void TokenStreamRouter::unregisterHandler(uint32_t streamId) {
    QMutexLocker lock(&m_mutex);
    m_handlers.remove(streamId);
}

void TokenStreamRouter::dispatchToken(uint32_t streamId, const QString& token) {
    QMutexLocker lock(&m_mutex);
    
    auto it = m_handlers.find(streamId);
    if (it != m_handlers.end()) {
        // Invoke handler on correct thread
        if (it->ownerThread == QThread::currentThread()) {
            it->callback(token);
        } else {
            // Cross-thread dispatch via Qt signal
            emit tokenAvailable(streamId, token);
        }
    }
}

void TokenStreamRouter::dispatchSystemMessage(const QString& message) {
    emit systemMessage(message);
}
