ModelSelectionDialog::ModelSelectionDialog(ModelLoaderBridge* loader, QWidget* parent)
    : QDialog(parent), m_loader(loader) {
    
    setWindowTitle("RawrXD Model Selection");
    resize(800, 600);
    
    // Layout
    auto* mainLayout = new QVBoxLayout(this);
    
    // Search bar
    m_searchEdit = new QLineEdit(this);
    m_searchEdit->setPlaceholderText("Search models...");
    mainLayout->addWidget(m_searchEdit);
    
    // Model list
    m_modelList = new QListWidget(this);
    mainLayout->addWidget(m_modelList);
    
    // Buttons
    auto* buttonLayout = new QHBoxLayout();
    
    m_refreshButton = new QPushButton("Refresh", this);
    m_loadButton = new QPushButton("Load Selected", this);
    m_loadButton->setEnabled(false);
    
    buttonLayout->addWidget(m_refreshButton);
    buttonLayout->addWidget(m_loadButton);
    
    mainLayout->addLayout(buttonLayout);
    
    // Connections
    connect(m_refreshButton, &QPushButton::clicked, this, &ModelSelectionDialog::onRefreshClicked);
    connect(m_loadButton, &QPushButton::clicked, this, &ModelSelectionDialog::onLoadClicked);
    connect(m_modelList, &QListWidget::itemDoubleClicked, this, &ModelSelectionDialog::onModelItemDoubleClicked);
    connect(m_loader, &ModelLoaderBridge::modelLoaded, this, &ModelSelectionDialog::onModelLoaded);
    
    // Initial population
    onRefreshClicked();
}

void ModelSelectionDialog::onRefreshClicked() {
    m_modelList->clear();
    
    auto models = m_loader->getAvailableModels();
    for (const auto& model : models) {
        auto* item = new QListWidgetItem(model.name);
        item->setData(Qt::UserRole, model.path);
        
        if (model.isLoaded) {
            item->setBackground(Qt::green);
            item->setText(item->text() + " [LOADED]");
        }
        
        m_modelList->addItem(item);
    }
}

void ModelSelectionDialog::onLoadClicked() {
    auto* currentItem = m_modelList->currentItem();
    if (!currentItem) return;
    
    QString modelPath = currentItem->data(Qt::UserRole).toString();
    emit modelLoadRequested(modelPath);
    
    // Show loading indicator
    m_loadButton->setText("Loading...");
    m_loadButton->setEnabled(false);
}

void ModelSelectionDialog::onModelItemDoubleClicked(QListWidgetItem* item) {
    QString modelPath = item->data(Qt::UserRole).toString();
    emit modelSelected(modelPath);
    accept();
}

void ModelSelectionDialog::onModelLoaded(const QString& name, uint64_t size) {
    QMessageBox::information(this, "Success", 
        QString("Loaded %1 (%.2f MB)").arg(name).arg(size / 1024.0 / 1024.0));
    
    m_loadButton->setText("Load Selected");
    m_loadButton->setEnabled(true);
    onRefreshClicked(); // Update loaded status
}
