#include "IDEIntegration.h"
#include "ModelSelectionDialog.h"
#include <QDebug>

IDEIntegration* IDEIntegration::instance() {
    static IDEIntegration* s_instance = nullptr;
    static QMutex mutex;
    
    QMutexLocker lock(&mutex);
    if (!s_instance) {
        s_instance = new IDEIntegration();
    }
    return s_instance;
