bool IDEIntegration::initialize() {
    if (m_initialized) return true;
    
    m_loader = std::make_unique<ModelLoaderBridge>();
    if (!m_loader->initialize(64, 16384)) {
        emit errorOccurred("Failed to initialize ModelLoaderBridge");
        return false;
    }
    
    m_cache = std::make_unique<ModelCacheManager>(m_loader.get());
    m_cache->setMaxCacheSizeGB(32);
    
    // Preload commonly used models
    m_cache->prefetchForTask("code_completion");
    m_cache->prefetchForTask("chat");
    
    m_completionSession = std::make_unique<InferenceSession>(m_loader.get());
    m_chatSession = std::make_unique<InferenceSession>(m_loader.get());
    
    m_initialized = true;
    qInfo() << "IDEIntegration: Fully initialized with Sovereign Loader";
    return true;
}

void IDEIntegration::shutdown() {
    if (!m_initialized) return;
    
    m_completionSession.reset();
    m_chatSession.reset();
    m_cache.reset();
    m_loader->shutdown();
    m_loader.reset();
    
    m_initialized = false;
}

void IDEIntegration::showModelSelector() {
    if (!m_initialized) return;
    
    auto* dialog = new ModelSelectionDialog(m_loader.get());
    connect(dialog, &ModelSelectionDialog::modelLoadRequested,
            this, &IDEIntegration::loadModel);
    connect(dialog, &ModelSelectionDialog::modelSelected,
            [this](const QString& path) {
                loadModel(path);
                emit modelReady(path);
            });
    
    dialog->setAttribute(Qt::WA_DeleteOnClose);
    dialog->show();
}

void IDEIntegration::loadModel(const QString& path) {
    if (!m_initialized) return;
    
    m_loader->loadModelAsync(path);
}

void IDEIntegration::startCodeCompletion(const QString& codeContext) {
    if (!m_initialized || !m_completionSession) return;
    
    // Auto-select appropriate model
    QString modelName = "phi-3-mini.gguf"; // Or from router
    
    if (m_completionSession->startSession(modelName)) {
        m_completionSession->inferStreaming(codeContext, 
            [this](const std::string& token) {
                emit inferenceResult(QString::fromStdString(token));
            });
    }
}
