#include "ModelMetadataParser.h"
#include <QFile>
#include <QDataStream>
#include <QDebug>

QHash<QString, QVariant> ModelMetadataParser::parseGGUFHeader(const QString& filePath) {
    QHash<QString, QVariant> metadata;
    
    QFile file(filePath);
    if (!file.open(QIODevice::ReadOnly)) {
        qWarning() << "Cannot open GGUF file:" << filePath;
        return metadata;
    }
    
    QDataStream stream(&file);
    stream.setByteOrder(QDataStream::LittleEndian);
    
    // Read header
    GGUFHeader header;
    stream >> header.magic;
    
    if (header.magic != 0x46554747) { // 'GGUF'
        qWarning() << "Invalid GGUF magic number";
        return metadata;
    }
    
    stream >> header.version;
    stream >> header.tensor_count;
    stream >> header.metadata_kv_count;
    
    // Parse metadata key-value pairs
    for (uint64_t i = 0; i < header.metadata_kv_count; ++i) {
        uint64_t keyLen;
        stream >> keyLen;
        
        QByteArray keyData;
        keyData.resize(keyLen);
        stream.readRawData(keyData.data(), keyLen);
        QString key = QString::fromUtf8(keyData);
        
        uint32_t valueType;
        stream >> valueType;
        
        // Simplified - in production, handle all GGUF types
        if (valueType == 0) { // uint32
            uint32_t value;
            stream >> value;
            metadata[key] = value;
        } else if (valueType == 1) { // string
            uint64_t strLen;
            stream >> strLen;
            QByteArray strData;
            strData.resize(strLen);
            stream.readRawData(strData.data(), strLen);
            metadata[key] = QString::fromUtf8(strData);
        }
    }
    
    return metadata;
}

QString ModelMetadataParser::getModelName(const QHash<QString, QVariant>& metadata) {
    return metadata.value("general.name", "Unknown").toString();
}

int ModelMetadataParser::getParameterCount(const QHash<QString, QVariant>& metadata) {
    return metadata.value("general.parameter_count", 0).toInt();
}

QString ModelMetadataParser::getQuantizationType(const QHash<QString, QVariant>& metadata) {
    return metadata.value("general.quantization_version", "Unknown").toString();
}
