    : QObject(parent) {
}

void StreamingInferenceEngine::completeCode(const QString& codeContext,
                                          InferenceSession::TokenCallback callback) {
    QString model = selectModelForTask("completion");
    
    auto* session = new InferenceSession(IDEIntegration::instance()->m_loader.get());
    if (session->startSession(model)) {
        connect(session, &InferenceSession::tokenGenerated,
                this, &StreamingInferenceEngine::tokenStreamed);
        connect(session, &InferenceSession::inferenceComplete,
                this, &StreamingInferenceEngine::inferenceComplete);
        
        session->inferStreaming(codeContext, callback);
    }
}

void StreamingInferenceEngine::chatMessage(const QString& message,
                                         InferenceSession::TokenCallback callback) {
    QString model = selectModelForTask("chat");
    
    auto* session = new InferenceSession(IDEIntegration::instance()->m_loader.get());
    if (session->startSession(model)) {
        session->inferStreaming(message, callback);
    }
}

QString StreamingInferenceEngine::selectModelForTask(const QString& taskType) {
    // Production logic: Select based on task complexity
    if (taskType == "completion") {
        return "phi-3-mini.gguf"; // Fast, low-latency
    } else if (taskType == "chat") {
        return "dolphin3.gguf"; // Conversational
    } else if (taskType == "test_gen") {
        return "qwen3-coder.gguf"; // Code specialized
    }
    
    return "phi-3-mini.gguf"; // Default
}
